305→// Zod schema for QueueState
306→const QueueStateSchema = z.object({
307→  lastUpdated: z.string(),
308→  queues: z.array(z.string()),
309→  stats: z.object({
310→    totalItems: z.number(),
311→    totalProcessed: z.number(),
312→    lastProcessedAt: z.string().optional(),
313→  }),
314→  lastCleanupAt: z.string().optional(),
315→});
316→
317→type QueueState = z.infer<typeof QueueStateSchema>;
318→
319→// StateManager instance for global queue state
320→const queueStateManager: StateManager<QueueState> = createStateManager({
321→  path: STATE_FILE,
322→  schema: QueueStateSchema,
323→  defaults: {
324→    lastUpdated: new Date().toISOString(),
325→    queues: [],
326→    stats: {
327→      totalItems: 0,
328→      totalProcessed: 0,
329→    },
330→  },
331→});
