333→// ============================================================================
334→// Helper Functions
335→// ============================================================================
336→
337→function ensureDir(dirPath: string): void {
338→  if (!existsSync(dirPath)) {
339→    mkdirSync(dirPath, { recursive: true });
340→  }
341→}
342→
343→/**
344→ * Archive queue items to per-queue archive JSONL files.
345→ * Path: MEMORY/QUEUES/archive/{queueName}-archive.jsonl
346→ * Uses appendFileSync for crash-safe append-only writes.
347→ */
348→export function archiveItems(queueName: string, items: QueueItem[]): void {
349→  if (items.length === 0) return;
350→  ensureDir(ARCHIVE_DIR);
351→  const archivePath = join(ARCHIVE_DIR, `${queueName}-archive.jsonl`);
352→  const content = items.map((item) => JSON.stringify(item)).join("\n") + "\n";
353→  appendFileSync(archivePath, content);
354→}
355→
356→export function generateId(): string {
357→  const timestamp = Date.now().toString(36);
358→  const random = Math.random().toString(36).slice(2, 8);
359→  return `${timestamp}-${random}`;
360→}
361→
362→export function getQueueFilePath(queueName: string): string {
363→  return join(QUEUES_DIR, `${queueName}.jsonl`);
364→}
365→
366→function loadRoutingConfig(): RoutingConfig {
367→  if (!existsSync(ROUTING_RULES_FILE)) {
368→    return {
369→      version: 1,
370→      routes: [{ pattern: "*", queue: "approvals", priority: 2, requiresApproval: true }],
371→      defaults: { priority: 2, expiryDays: 30 },
372→    };
373→  }
374→
375→  const content = readFileSync(ROUTING_RULES_FILE, "utf-8");
376→  return parseYaml(content) as RoutingConfig;
377→}
378→
379→function matchPattern(pattern: string, input: string): boolean {
380→  // Simple glob matching
381→  if (pattern === "*") return true;
382→  if (pattern.endsWith("*")) {
383→    const prefix = pattern.slice(0, -1);
384→    return input.startsWith(prefix);
385→  }
386→  return pattern === input;
387→}
388→
389→function routeItem(typeOrTitle: string): { queue: string; priority: Priority; requiresApproval: boolean } {
390→  const config = loadRoutingConfig();
391→
392→  for (const rule of config.routes) {
393→    if (matchPattern(rule.pattern, typeOrTitle)) {
394→      return {
395→        queue: rule.queue,
396→        priority: rule.priority ?? config.defaults.priority,
397→        requiresApproval: rule.requiresApproval ?? false,
398→      };
399→    }
400→  }
401→
402→  return {
403→    queue: "approvals",
404→    priority: config.defaults.priority,
405→    requiresApproval: true,
406→  };
407→}
408→
409→export function loadQueueItems(queueName: string): QueueItem[] {
410→  const filePath = getQueueFilePath(queueName);
411→  if (!existsSync(filePath)) {
412→    return [];
413→  }
414→
415→  const content = readFileSync(filePath, "utf-8");
416→  const lines = content.trim().split("\n").filter(Boolean);
417→  let droppedLines = 0;
418→
419→  const items = lines.map((line, index) => {
420→    try {
421→      return JSON.parse(line) as QueueItem;
422→    } catch (err) {
423→      droppedLines++;
424→      console.error(`[QueueManager] Corrupt JSONL line ${index + 1} in ${queueName}.jsonl: ${err instanceof Error ? err.message : err}`);
425→      return null;
426→    }
427→  }).filter((item): item is QueueItem => item !== null);
428→
429→  if (droppedLines > 0) {
430→    console.error(`[QueueManager] WARNING: Dropped ${droppedLines} corrupt line(s) from ${queueName}.jsonl (${items.length} valid items loaded)`);
431→  }
432→
433→  return items;
434→}
435→
436→export function saveQueueItems(queueName: string, items: QueueItem[]): void {
437→  ensureDir(QUEUES_DIR);
438→  const filePath = getQueueFilePath(queueName);
439→  const content = items.map((item) => JSON.stringify(item)).join("\n");
440→  const tmpPath = filePath + ".tmp." + process.pid;
441→  writeFileSync(tmpPath, content + (content ? "\n" : ""));
442→  renameSync(tmpPath, filePath);
443→}
444→
445→export function appendQueueItem(queueName: string, item: QueueItem): void {
446→  ensureDir(QUEUES_DIR);
447→  const filePath = getQueueFilePath(queueName);
448→  appendFileSync(filePath, JSON.stringify(item) + "\n");
449→}
450→
451→/**
452→ * Load global queue state using CORE StateManager
453→ * Synchronous wrapper for CLI compatibility
454→ */
455→function loadState(): QueueState {
456→  // Use sync read for CLI commands (StateManager.load is async)
457→  if (!existsSync(STATE_FILE)) {
458→    return {
459→      lastUpdated: new Date().toISOString(),
460→      queues: [],
461→      stats: { totalItems: 0, totalProcessed: 0 },
462→    };
463→  }
464→
465→  try {
466→    const raw = readFileSync(STATE_FILE, "utf-8");
467→    const parsed = JSON.parse(raw);
468→    // Remove internal version field if present
469→    const { _version, ...stateData } = parsed;
470→    const result = QueueStateSchema.safeParse(stateData);
471→    return result.success ? result.data : {
472→      lastUpdated: new Date().toISOString(),
473→      queues: [],
474→      stats: { totalItems: 0, totalProcessed: 0 },
475→    };
476→  } catch {
477→    return {
478→      lastUpdated: new Date().toISOString(),
479→      queues: [],
480→      stats: { totalItems: 0, totalProcessed: 0 },
481→    };
482→  }
483→}
484→
485→/**
486→ * Save global queue state using CORE StateManager
487→ */
488→async function saveStateAsync(state: QueueState): Promise<void> {
489→  await queueStateManager.save(state);
490→}
491→
492→/**
493→ * Synchronous state save for compatibility
494→ */
495→function saveState(state: QueueState): void {
496→  ensureDir(QUEUES_DIR);
497→  state.lastUpdated = new Date().toISOString();
498→  writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
499→}

500→
501→function discoverQueues(): string[] {
502→  ensureDir(QUEUES_DIR);
503→  const files = readdirSync(QUEUES_DIR);
504→  return files
505→    .filter((f) => f.endsWith(".jsonl"))
506→    .map((f) => basename(f, ".jsonl"));
507→}
