509→// ============================================================================
510→// QueueManager Class
511→// ============================================================================
512→
513→export class QueueManager {
514→  /**
515→   * Add a new item to a queue
516→   */
517→  async add(
518→    payload: { title: string; description: string; context?: Record<string, unknown> },
519→    options: AddOptions = {}
520→  ): Promise<string> {
521→    const type = options.type || "task";
522→    const routing = routeItem(`${type}:${payload.title}`);
523→
524→    // When a spec is provided, route directly to approvals (bypass spec-pipeline)
525→    const queueName = options.spec
526→      ? (options.queue || "approvals")
527→      : (options.queue || routing.queue);
528→    const priority = options.priority || routing.priority;
529→
530→    // Spec-pipeline delegation: items without a spec go through spec-pipeline first
531→    if (queueName === "spec-pipeline" && !options.spec) {
532→      return this.addSpecPipelineItem(payload, {
533→        id: options.id,
534→        priority,
535→        type,
536→        source: options.source,
537→        context: options.context,
538→      });
539→    }
540→
541→    // Approvals guard: nothing enters approvals without a spec (defense in depth)
542→    if (queueName === "approvals" && !options.spec) {
543→      throw new Error(
544→        `Cannot add item to approvals without a spec. ` +
545→        `Items must go through spec-pipeline first, or use --spec to attach an existing spec.`
546→      );
547→    }
548→
549→    const item: QueueItem = {
550→      id: options.id || generateId(),
551→      created: new Date().toISOString(),
552→      updated: new Date().toISOString(),
553→      source: options.source || "manual",
554→      priority,
555→      status: routing.requiresApproval ? "awaiting_approval" : "pending",
556→      type,
557→      queue: queueName,
558→      payload: {
559→        title: payload.title,
560→        description: payload.description,
561→        context: payload.context || options.context,
562→      },
563→      routing: {
564→        targetQueue: queueName,
565→      },
566→      ...(options.notes ? { result: { reviewNotes: options.notes } } : {}),
567→      ...(options.spec ? { spec: options.spec } : {}),
568→    };
569→
570→    // Idempotency: skip if item with same custom ID already exists and is not terminal
571→    if (options.id) {
572→      const existing = loadQueueItems(queueName);
573→      const match = existing.find(i => i.id === options.id && i.status !== "completed" && i.status !== "failed");
574→      if (match) {
575→        return match.id;
576→      }
577→    }
578→
579→    appendQueueItem(queueName, item);
580→
581→    // Update state
582→    const state = loadState();
583→    if (!state.queues.includes(queueName)) {
584→      state.queues.push(queueName);
585→    }
586→    state.stats.totalItems++;
587→    saveState(state);
588→
589→    return item.id;
590→  }
591→
592→  /**
593→   * Get a specific item by ID
594→   */
595→  async get(id: string): Promise<QueueItem | null> {
596→    const queues = discoverQueues();
597→
598→    for (const queueName of queues) {
599→      const items = loadQueueItems(queueName);
600→      const item = items.find((i) => i.id === id);
601→      if (item) return item;
602→    }
603→
604→    return null;
605→  }
606→
607→  /**
608→   * List items with optional filtering
609→   */
610→  async list(filter: ListFilter = {}): Promise<QueueItem[]> {
611→    const queues = filter.queue ? [filter.queue] : discoverQueues();
612→    let allItems: QueueItem[] = [];
613→
614→    for (const queueName of queues) {
615→      const items = loadQueueItems(queueName);
616→      allItems = allItems.concat(items);
617→    }
618→
619→    // Apply filters
620→    if (filter.status) {
621→      allItems = allItems.filter((i) => i.status === filter.status);
622→    }
623→    if (filter.priority) {
624→      allItems = allItems.filter((i) => i.priority === filter.priority);
625→    }
626→    if (filter.type) {
627→      allItems = allItems.filter((i) => i.type === filter.type);
628→    }
629→
630→    // Sort by priority (ascending - 1 is highest) then by created date
631→    allItems.sort((a, b) => {
632→      if (a.priority !== b.priority) {
633→        return a.priority - b.priority;
634→      }
635→      return new Date(a.created).getTime() - new Date(b.created).getTime();
636→    });
637→
638→    return allItems;
639→  }
640→
641→  /**
642→   * Get the next pending item from a queue
643→   */
644→  async next(queueName?: string): Promise<QueueItem | null> {
645→    const items = await this.list({
646→      queue: queueName,
647→      status: "pending",
648→    });
649→
650→    return items[0] || null;
651→  }
652→
653→  /**
654→   * Update an item
655→   */
656→  async update(id: string, updates: UpdateOptions): Promise<QueueItem | null> {
657→    const queues = discoverQueues();
658→
659→    for (const queueName of queues) {
660→      const items = loadQueueItems(queueName);
661→      const index = items.findIndex((i) => i.id === id);
662→
663→      if (index !== -1) {
664→        const item = items[index];
665→        item.updated = new Date().toISOString();
666→
667→        if (updates.status) {
668→          item.status = updates.status;
669→        }
670→        if (updates.assignedAgent) {
671→          item.routing = item.routing || {};
672→          item.routing.assignedAgent = updates.assignedAgent;
673→        }
674→        if (updates.output !== undefined) {
675→          item.result = item.result || {};
676→          item.result.output = updates.output;
677→        }
678→        if (updates.error) {
679→          item.result = item.result || {};
680→          item.result.error = updates.error;
681→        }
682→
683→        saveQueueItems(queueName, items);
684→
685→        // Sync state after update
686→        const state = loadState();
687→        state.lastUpdated = new Date().toISOString();
688→        saveState(state);
689→
690→        return item;
691→      }
692→    }
693→
694→    return null;
695→  }
